// Extract Lead Fields with safe optional chaining
// Webhook payload is in body object
const raw = $('New Lead Webhook').first().json;
const body = raw.body || raw; // Handle both webhook body and direct data
const payloadId = $input.first().json.id;

// Try multiple possible field paths for each value
const getName = () => {
  return body.name || body.contact_name || body.customer_name || 
         body.lead?.name || body.contact?.name || body.customer?.name ||
         (body.first_name ? `${body.first_name} ${body.last_name || ''}`.trim() : null) ||
         body.data?.name || body.data?.contact_name || 'Unknown';
};

const getPhone = () => {
  return body.phone || body.phone_number || body.mobile || body.cell ||
         body.contact_phone || body.customer_phone ||
         body.lead?.phone || body.contact?.phone || body.customer?.phone ||
         body.data?.phone || body.data?.phone_number || '';
};

const getEmail = () => {
  return body.email || body.email_address || body.contact_email ||
         body.lead?.email || body.contact?.email || body.customer?.email ||
         body.data?.email || '';
};

const getServiceType = () => {
  return body.service_type || body.service || body.project_type || body.type ||
         body.lead?.service_type || body.job?.type ||
         body.data?.service_type || body.description || 'home improvement';
};

const getSource = () => {
  return body.source || body.lead_source || body.referral_source ||
         body.lead?.source || body.data?.source || 'webhook';
};

const getJobtreadId = () => {
  return body.id || body.lead_id || body.jobtread_id || body.job_id ||
         body.lead?.id || body.data?.id || null;
};

// Phone normalization to E.164
const normalizePhone = (phone) => {
  if (!phone) return null;
  // Remove all non-digit characters
  let digits = phone.toString().replace(/\D/g, '');

  // Handle US numbers
  if (digits.length === 10) {
    return '+1' + digits;
  } else if (digits.length === 11 && digits.startsWith('1')) {
    return '+' + digits;
  } else if (digits.length > 10) {
    // Assume already has country code
    return '+' + digits;
  }
  return null; // Invalid phone
};

const phone = getPhone();
const phoneE164 = normalizePhone(phone);

return {
  json: {
    payload_id: payloadId,
    jobtread_id: getJobtreadId(),
    name: getName(),
    phone: phone,
    phone_e164: phoneE164,
    email: getEmail(),
    service_type: getServiceType(),
    source: getSource(),
    valid_phone: phoneE164 !== null
  }
};

// Check Business Hours - Mountain Time (America/Denver) with DST
const lead = $input.first().json;

// Get current time in Denver timezone
const now = new Date();
const denverOptions = { timeZone: 'America/Denver', hour12: false };
const denverTimeStr = now.toLocaleString('en-US', {
  timeZone: 'America/Denver',
  hour: '2-digit',
  minute: '2-digit',
  weekday: 'short',
  hour12: false
});

// Parse Denver time components
const denverDate = new Date(now.toLocaleString('en-US', { timeZone: 'America/Denver' }));
const hour = denverDate.getHours();
const dayOfWeek = denverDate.getDay(); // 0 = Sunday

// Business hours: 7am-7pm Mon-Sat (days 1-6)
const isBusinessDay = dayOfWeek >= 1 && dayOfWeek <= 6;
const isBusinessHours = hour >= 7 && hour < 19; // 7am to 7pm
const isOpen = isBusinessDay && isBusinessHours;

// Calculate next business day 8am if currently closed
let nextOpenTime = null;
if (!isOpen) {
  const next = new Date(denverDate);

  if (dayOfWeek === 0) {
    // Sunday -> Monday 8am
    next.setDate(next.getDate() + 1);
  } else if (dayOfWeek === 6 && hour >= 19) {
    // Saturday after 7pm -> Monday 8am
    next.setDate(next.getDate() + 2);
  } else if (hour >= 19) {
    // After hours weekday -> next day 8am
    next.setDate(next.getDate() + 1);
  }
  // Else before 7am same day

  next.setHours(8, 0, 0, 0);
  nextOpenTime = next.toISOString();
}

return {
  json: {
    ...lead,
    is_business_hours: isOpen,
    current_denver_time: denverTimeStr,
    next_open_time: nextOpenTime,
    hour: hour,
    day_of_week: dayOfWeek
  }
};

// Error Handler
const error = $input.first();
let errorMsg = '';
try {
  errorMsg = error.json?.message || error.json?.error || JSON.stringify(error.json || {});
} catch(e) {
  errorMsg = 'Unknown error';
}

return {
  json: {
    workflow_name: 'Lead Response Automation',
    node_name: 'Unknown',
    error_message: errorMsg.substring(0, 2000),
    raw_payload: error.json || {}
  }
};

